# This script compacts an XML font's metadata generated by BMFont.
# It removes optional, not used here tags, etc.
# Everything for more effecitve work at the app's runtime.

if ($args.length -ne 1)
{
	Write-Error "${MyInvocation.MyCommand.Name}: Incorrect number of parameters, should be: <Monad Font Name>"
	[System.Console]::Beep()
	exit 1
}

. (Join-Path $PSScriptRoot 'XMLLib.ps1')
Set-Variable StyleBold -Option ReadOnly -Value '_bold'
Set-Variable StyleItalic -Option ReadOnly -Value '_italic'

# This code merges 4 XMLS into 1. It is because fonts can be italics, etc.
'<monad>' + (@($args[0], ($args[0] + $StyleBold), ($args[0] + $StyleItalic), ($args[0] + $StyleBold + $StyleItalic))|
ForEach-Object { Join-Path 'Res' ($_ + '.fnt') }|
Where-Object { Test-Path($_) }|
ForEach-Object {
	Remove-MonadSpace(
		Remove-MonadHeader(
			Remove-MonadAttributes(
				Remove-MonadTag(
					Get-Content $_) 'pages') @(
			'face', 'size', 'charset', 'unicode', 'smooth',
			'aa', 'padding', 'spacing', 'outline', 'stretchH',
			'alphaChnl', 'redChnl', 'greenChnl', 'blueChnl', 'base',
			'pages', 'packed', 'page', 'chnl')).`
		Replace('second', 'sec').`
		Replace('xadvance', 'adv').`
		Replace('width', 'w').`
		Replace('height', 'h').`
		Replace('amount', 'amt').`
		Replace('count', 'cnt').`
		Replace('xoffset', 'xofs').`
		Replace('yoffset', 'yofs').`
		Replace('kerning', 'k').`
		Replace('char', 'c').`
		Replace('first', 'frst').`
		Replace('lineHeight', 'lnH').`
		Replace('font', 'fnt').`
		Replace('bold', 'b').`
		Replace('italic', 'i').`
		Replace('info', 'inf').`
		Replace('common', 'cmn'))`
}) + "</monad>`0"|
Out-File -NoNewline -FilePath (Join-Path 'Release' ($args[0] + '.CmpXML'))